    ```java
class NaryTreeNode {
    int val;
    List<NaryTreeNode> children;
}

class BinaryTreeNode {
    int val;
    BinaryTreeNode left, right;
}

public BinaryTreeNode encode(NaryTreeNode root) {
    if (root == null) return null;
    BinaryTreeNode binaryRoot = new BinaryTreeNode();
    binaryRoot.val = root.val;
    if (root.children.size() > 0)
        binaryRoot.left = encode(root.children.get(0));
    BinaryTreeNode sibling = binaryRoot.left;
    for (int i = 1; i < root.children.size(); ++i) {
        sibling.right = encode(root.children.get(i));
        sibling = sibling.right;
    }
    return binaryRoot;
}

public NaryTreeNode decode(BinaryTreeNode root) {
    if (root == null) return null;
    NaryTreeNode naryRoot = new NaryTreeNode();
    naryRoot.val = root.val;
    naryRoot.children = new ArrayList<>();
    BinaryTreeNode sibling = root.left;
    while (sibling != null) {
        naryRoot.children.add(decode(sibling));
        sibling = sibling.right;
    }
    return naryRoot;
}
```

